import React, { useState } from "react";
import axios from "axios";

function KeywordPage() {
  const [text, setText] = useState("");
  const [keywords, setKeywords] = useState(null);
  const [error, setError] = useState("");

  const handleExtract = async () => {
    try {
      setError("");
      setKeywords(null);

      const res = await axios.post("http://localhost:3000/api/keywords", {
        text: text,
      });

      setKeywords(res.data);
    } catch (err) {
      console.error(err);
      setError("Keyword extraction failed.");
    }
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Keyword Extraction</h2>

      <textarea
        rows={5}
        value={text}
        onChange={(e) => setText(e.target.value)}
        placeholder="Enter text for keyword extraction"
        style={{
          width: "100%",
          marginBottom: "10px",
          padding: "10px",
        }}
      />

      <br />
      <button onClick={handleExtract}>Extract Keywords</button>

      {error && <p style={{ color: "red" }}>{error}</p>}

      {keywords && (
        <div style={{ marginTop: "20px" }}>
          <h4>Keywords:</h4>
          <ul>
            {keywords[0]?.length > 0 ? (
              keywords[0].map((kw, index) => (
                <li key={index}>{kw}</li>
              ))
            ) : (
              <li>No keywords found.</li>
            )}
          </ul>
        </div>
      )}
    </div>
  );
}

export default KeywordPage;
